import re

class Solution:
    def countValidWords(self, sentence: str) -> int:
        pattern = re.compile(r'^([a-z]+(-[a-z]+)?)?[!.,]?$')
        count = 0
        for tok in sentence.split(' '):
            if tok == '':
                continue
            if pattern.match(tok):
                count += 1
        return count

