class Solution:
    def countValidWords(self, sentence: str) -> int:
        def is_valid(word):
            hyphen = 0
            punct = 0
            n = len(word)
            for i, ch in enumerate(word):
                if ch.isdigit():
                    return False
                elif ch == '-':
                    hyphen += 1
                    if hyphen > 1:
                        return False
                    if i == 0 or i == n - 1:
                        return False
                    if not word[i-1].islower() or not word[i+1].islower():
                        return False
                elif ch in '!.,':
                    punct += 1
                    if punct > 1:
                        return False
                    if i != n - 1:
                        return False
                elif ch.islower():
                    continue
                else:
                    return False
            return True
        return sum(1 for tok in sentence.split(' ') if tok and is_valid(tok))

