var countValidWords = function(sentence) {
    function isValid(word) {
        let hyphen = 0, punct = 0;
        const n = word.length;
        for (let i = 0; i < n; i++) {
            const ch = word[i];
            if (ch >= '0' && ch <= '9') {
                return false;
            } else if (ch === '-') {
                hyphen++;
                if (hyphen > 1) return false;
                if (i === 0 || i === n - 1) return false;
                const prev = word[i-1], next = word[i+1];
                if (!(prev >= 'a' && prev <= 'z') || !(next >= 'a' && next <= 'z')) return false;
            } else if (ch === '!' || ch === '.' || ch === ',') {
                punct++;
                if (punct > 1) return false;
                if (i !== n - 1) return false;
            } else if (ch >= 'a' && ch <= 'z') {
                continue;
            } else {
                return false;
            }
        }
        return true;
    }
    return sentence.split(' ').filter(tok => tok.length > 0 && isValid(tok)).length;
};
